#!/usr/bin/env python3
"""
ARC Task 0934a4d8 Solver
Hypothesis: 8-Block Row/Column Intersection Extraction
- Find all rows containing color 8
- Find all cols containing color 8  
- Extract the rectangular region at their intersection
"""

import json
import numpy as np
from typing import List, Dict, Tuple

def solve_0934a4d8(grid: List[List[int]]) -> List[List[int]]:
    """
    Solve ARC task 0934a4d8 by extracting the region defined by:
    - All rows that contain color 8
    - All columns that contain color 8
    - The intersection of these rows and columns
    """
    input_grid = np.array(grid)
    h, w = input_grid.shape
    
    # Find all rows containing color 8
    rows_with_8 = set()
    for i in range(h):
        if 8 in input_grid[i, :]:
            rows_with_8.add(i)
    
    # Find all columns containing color 8
    cols_with_8 = set()
    for j in range(w):
        if 8 in input_grid[:, j]:
            cols_with_8.add(j)
    
    # If no color 8 found, return empty grid
    if not rows_with_8 or not cols_with_8:
        return [[]]
    
    # Get the bounding box of the 8-block
    min_row = min(rows_with_8)
    max_row = max(rows_with_8)
    min_col = min(cols_with_8)
    max_col = max(cols_with_8)
    
    # Extract the rectangular region at the intersection
    output = input_grid[min_row:max_row+1, min_col:max_col+1]
    
    return output.tolist()


def test_solution(task_data: Dict) -> Tuple[int, int, List[str]]:
    """Test the solution against training examples"""
    correct = 0
    total = len(task_data['train'])
    details = []
    
    for i, pair in enumerate(task_data['train']):
        input_grid = pair['input']
        expected_output = pair['output']
        
        prediction = solve_0934a4d8(input_grid)
        
        # Check if prediction matches expected
        if prediction == expected_output:
            correct += 1
            details.append(f"Example {i+1}: CORRECT ✓")
        else:
            # Check dimensions
            pred_shape = (len(prediction), len(prediction[0]) if prediction else 0)
            exp_shape = (len(expected_output), len(expected_output[0]) if expected_output else 0)
            
            if pred_shape == exp_shape:
                # Same size but different content
                diff_count = sum(1 for r in range(len(prediction)) 
                                for c in range(len(prediction[0])) 
                                if prediction[r][c] != expected_output[r][c])
                details.append(f"Example {i+1}: WRONG (shape match, {diff_count} cells differ)")
            else:
                details.append(f"Example {i+1}: WRONG (shape: got {pred_shape}, expected {exp_shape})")
    
    return correct, total, details


